import React, { useState } from "react";
import PortfolioPortal from "./PortfolioPortal";
import { socialLinks, footLinks } from "./Utils";
import {
	IconButton,
	Button,
} from "@material-ui/core";

const Footer = () => {
	const [showPortal, setShowPortal] =
		useState(false);

	return (
		<React.Fragment>
			<div className="BottomColor"></div>
			<div className="foot">
				<div className="leftPanel">
					{footLinks.map((link) => {
						return (
							<Button
								key={link.name}
								onClick={() => {
									setShowPortal(!showPortal);
									setTimeout(() => {
										document.documentElement.scrollTop =
											link.no;
									}, 200);
								}}
								title={link.title}
							>
								{link.name}
							</Button>
						);
					})}
				</div>

				<div className="socials">
					<div className="socialButtons">
						{socialLinks.map((social) => {
							return (
								<IconButton
									key={social.name}
									title={social.name}
									href={social.href}
								>
									{social.icon}
								</IconButton>
							);
						})}
					</div>
				</div>
				<div className="copyx0">
					<h5>
						David's Portfolio &copy; 2021. All
						Rights Reserved.
					</h5>
				</div>
			</div>
			<PortfolioPortal
				showPortal={showPortal}
				setShowPortal={setShowPortal}
			/>
		</React.Fragment>
	);
};

export default Footer;
